import{_ as t,o as l,c as i,a2 as a}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Example plugins plan","description":"","frontmatter":{},"headers":[],"relativePath":"adhoc/example-plugins-plan.md","filePath":"adhoc/example-plugins-plan.md"}'),o={name:"adhoc/example-plugins-plan.md"};function n(s,e,d,r,p,c){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="example-plugins-plan" tabindex="-1">Example plugins plan <a class="header-anchor" href="#example-plugins-plan" aria-label="Permalink to &quot;Example plugins plan&quot;">​</a></h1><p><strong>Status:</strong> Partially implemented <strong>Scope:</strong> Adhoc implementation blueprint outside the main roadmap <strong>Retention:</strong> Keep after implementation as a planning and decision log</p><p>This document captures the planned example plugin set for Sovereign. It is a documentation-first implementation plan: no code should be changed from this document alone. Future implementation tasks should cite this plan, update the adhoc task status in this document, and then make the corresponding code, registry, and documentation changes.</p><p>Documents under <code>docs/adhoc/</code> track implementation plans that should stay outside the canonical roadmap/epic queue. They are retained after completion as lightweight logs of scope, decisions, and follow-up work.</p><h2 id="implementation-log" tabindex="-1">Implementation log <a class="header-anchor" href="#implementation-log" aria-label="Permalink to &quot;Implementation log&quot;">​</a></h2><h3 id="_2026-07-02" tabindex="-1">2026-07-02 <a class="header-anchor" href="#_2026-07-02" aria-label="Permalink to &quot;2026-07-02&quot;">​</a></h3><ul><li>Tightened the manifest schema so code accepts only <code>runtime: &quot;native&quot;</code>; future runtime models remain documented as planned/deferred.</li><li>Added <code>Example: Overlay Small</code>, <code>Example: Overlay Medium</code>, and <code>Example: Overlay Large</code> as separate plugins because overlay size is manifest-level configuration.</li><li>Added <code>Example: Minimal</code> for the chrome-free shell mode.</li><li>Expanded <code>Example: API</code> into the active <code>apiProvider: true</code> reference with deterministic GET/POST delegated routes and structured errors.</li><li>Expanded <code>Example: Monetized</code> with explicit manifest, middleware, and reserved SDK billing notes.</li><li>Updated the generated registry and plugin development docs for the seven local examples.</li><li>Remaining: externalize shippable example sources into first-party repository infrastructure and wire them into default install configuration.</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Ship a small, coherent set of example plugins that demonstrate the platform&#39;s supported plugin surfaces.</li><li>Keep examples installable by default, while moving their primary source out of the main platform repository.</li><li>Keep the main repository focused on the platform runtime, SDK, tests, and deterministic fixtures.</li><li>Avoid exposing not-yet-implemented runtime models as accepted manifest values.</li><li>Preserve the current documentation-first workflow: plan, document, task, then implement.</li></ul><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li>Do not introduce new runtime models as part of the example plugin work.</li><li>Do not implement iframe, remote, or external plugin runtimes yet.</li><li>Do not make example plugins full product plugins. They are teaching artifacts and regression fixtures, not end-user apps.</li><li>Do not remove deterministic test coverage just because the shippable examples move out of the main repository.</li></ul><h2 id="final-example-set" tabindex="-1">Final example set <a class="header-anchor" href="#final-example-set" aria-label="Permalink to &quot;Final example set&quot;">​</a></h2><p>The default example set should contain seven installed example plugins. Product UI should continue using &quot;app&quot; for end-user labels where appropriate, but these developer-facing examples may use &quot;plugin&quot; in docs and source.</p><table tabindex="0"><thead><tr><th>Display name</th><th>Purpose</th><th>Primary surface demonstrated</th></tr></thead><tbody><tr><td><code>Example: Basic</code></td><td>Normal native plugin</td><td><code>runtime: &quot;native&quot;</code>, <code>shell: &quot;default&quot;</code></td></tr><tr><td><code>Example: Overlay Small</code></td><td>Small overlay dialog</td><td><code>shell: &quot;overlay&quot;</code>, <code>overlaySize: &quot;sm&quot;</code></td></tr><tr><td><code>Example: Overlay Medium</code></td><td>Medium overlay dialog</td><td><code>shell: &quot;overlay&quot;</code>, <code>overlaySize: &quot;md&quot;</code></td></tr><tr><td><code>Example: Overlay Large</code></td><td>Large overlay dialog</td><td><code>shell: &quot;overlay&quot;</code>, <code>overlaySize: &quot;lg&quot;</code></td></tr><tr><td><code>Example: Minimal</code></td><td>Full-screen/chrome-free plugin</td><td><code>shell: &quot;minimal&quot;</code></td></tr><tr><td><code>Example: API</code></td><td>Public API namespace provider</td><td><code>apiProvider: true</code></td></tr><tr><td><code>Example: Monetized</code></td><td>Paid plugin and entitlement gating</td><td><code>monetization</code>, paywall, license import flow</td></tr></tbody></table><p>The three overlay examples are intentionally separate plugins because <code>shellConfig.overlaySize</code> is manifest-level configuration. A single plugin cannot show all three sizes at runtime without changing its manifest. Separate plugins make the behavior honest, visible, and easy to test.</p><h2 id="example-details" tabindex="-1">Example details <a class="header-anchor" href="#example-details" aria-label="Permalink to &quot;Example details&quot;">​</a></h2><h3 id="example-basic" tabindex="-1">Example: Basic <a class="header-anchor" href="#example-basic" aria-label="Permalink to &quot;Example: Basic&quot;">​</a></h3><p>Keep the existing <code>Example: Basic</code> concept. It remains the default &quot;first plugin&quot; reference.</p><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;default&quot;</code> or omitted</li><li><code>permissions</code>: at least <code>auth:session</code></li><li><code>capabilities</code>: include one simple plugin-declared capability with <code>defaultGrant: &quot;all&quot;</code> so developers can see the namespaced capability pattern.</li></ul><p>Demonstrates:</p><ul><li>Reading the current session with <code>sdk.auth</code>.</li><li>Using <code>@sovereignfs/ui</code> components.</li><li>Styling with <code>--sv-*</code> design tokens.</li><li>Checking a plugin-declared capability with <code>sdk.auth.hasCapability</code>.</li><li>Explaining <code>adminOnly</code> as a nearby manifest option.</li></ul><p>Implementation notes:</p><ul><li>Do not enable <code>adminOnly</code> on this plugin by default. The Basic example should stay visible to all authenticated users.</li><li>Document <code>adminOnly</code> in the page or plugin README as the route-level admin-gating option.</li><li>Keep code minimal and stable. This plugin should be the easiest one to copy.</li></ul><h3 id="example-overlay-small" tabindex="-1">Example: Overlay Small <a class="header-anchor" href="#example-overlay-small" aria-label="Permalink to &quot;Example: Overlay Small&quot;">​</a></h3><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;overlay&quot;</code></li><li><code>shellConfig.overlaySize: &quot;sm&quot;</code></li><li><code>permissions</code>: <code>auth:session</code></li></ul><p>Demonstrates:</p><ul><li>Compact interruption-style overlay UI.</li><li>Platform-owned dialog chrome.</li><li>Hard-load fallback to a full page.</li><li>No plugin-owned modal wrapper.</li></ul><p>Implementation notes:</p><ul><li>Keep content intentionally small: a compact settings or quick-action form.</li><li>Include one intra-overlay navigation action that uses replace navigation, matching the overlay routing rule.</li></ul><h3 id="example-overlay-medium" tabindex="-1">Example: Overlay Medium <a class="header-anchor" href="#example-overlay-medium" aria-label="Permalink to &quot;Example: Overlay Medium&quot;">​</a></h3><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;overlay&quot;</code></li><li><code>shellConfig.overlaySize: &quot;md&quot;</code></li><li><code>permissions</code>: <code>auth:session</code></li></ul><p>Demonstrates:</p><ul><li>Medium dialog layout for workflows with multiple controls.</li><li>Overlay route composition and hard-load fallback.</li><li>Stable dimensions independent of content height.</li></ul><p>Implementation notes:</p><ul><li>Use a two-section form or preview surface.</li><li>Keep the structure similar to the small and large examples so the size difference is the main thing developers notice.</li></ul><h3 id="example-overlay-large" tabindex="-1">Example: Overlay Large <a class="header-anchor" href="#example-overlay-large" aria-label="Permalink to &quot;Example: Overlay Large&quot;">​</a></h3><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;overlay&quot;</code></li><li><code>shellConfig.overlaySize: &quot;lg&quot;</code></li><li><code>permissions</code>: <code>auth:session</code></li></ul><p>Demonstrates:</p><ul><li>Large overlay layout for settings, admin, or quick management workflows.</li><li>The default overlay size when <code>overlaySize</code> is omitted.</li><li>Multi-section content inside platform-owned dialog chrome.</li></ul><p>Implementation notes:</p><ul><li>This can be the most content-rich overlay example, but it should still avoid becoming a product app.</li><li>Mention that <code>lg</code> is the default overlay size.</li></ul><h3 id="example-minimal" tabindex="-1">Example: Minimal <a class="header-anchor" href="#example-minimal" aria-label="Permalink to &quot;Example: Minimal&quot;">​</a></h3><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;minimal&quot;</code></li><li><code>permissions</code>: <code>auth:session</code></li></ul><p>Demonstrates:</p><ul><li>Chrome-free, full-bleed plugin composition.</li><li>Plugin-owned navigation because the platform shell is absent.</li><li>Good use cases: kiosk display, canvas/editor, wallboard, immersive workflow.</li></ul><p>Implementation notes:</p><ul><li>Make the visual layout clearly different from a default-shell page.</li><li>Include an obvious way back to the Launcher or root route because the platform sidebar/header is absent.</li><li>Prefer a simple fullscreen control surface, dashboard, or canvas-like view.</li></ul><h3 id="example-api" tabindex="-1">Example: API <a class="header-anchor" href="#example-api" aria-label="Permalink to &quot;Example: API&quot;">​</a></h3><p>Keep the existing <code>Example: API</code> concept and expand it.</p><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;default&quot;</code></li><li><code>apiProvider: true</code></li><li><code>permissions</code>: whichever permissions are actually required by the example</li></ul><p>Demonstrates:</p><ul><li>Public <code>/api/*</code> namespace delegation.</li><li>The one-provider-per-instance rule.</li><li>Mapping from <code>/api/&lt;slug&gt;/*</code> to the plugin serve route.</li><li>Route handlers for at least one <code>GET</code> request and one <code>POST</code> request.</li><li>Structured success and error responses.</li><li>A lightweight API-key or signed-request pattern if that is the intended guidance for public API consumers.</li></ul><p>Implementation notes:</p><ul><li>The page should show concrete request examples and expected responses.</li><li>The route handlers should be deliberately simple and deterministic.</li><li>Avoid implying that all plugin pages are public. Only the delegated API namespace is public.</li></ul><h3 id="example-monetized" tabindex="-1">Example: Monetized <a class="header-anchor" href="#example-monetized" aria-label="Permalink to &quot;Example: Monetized&quot;">​</a></h3><p>Keep the existing <code>Example: Monetized</code> concept and expand the explanation.</p><p>Manifest intent:</p><ul><li><code>runtime: &quot;native&quot;</code></li><li><code>shell: &quot;default&quot;</code></li><li><code>type: &quot;sovereign&quot;</code> or <code>community</code></li><li><code>monetization</code> with a paid model, tiers, and Ed25519 public key</li><li><code>permissions</code>: <code>auth:session</code></li></ul><p>Demonstrates:</p><ul><li>Manifest-declared monetization.</li><li>Platform paywall behavior.</li><li>Offline Ed25519 license verification.</li><li>License import flow through Account.</li><li>Entitlement visibility through Console.</li><li>Tier-aware UI patterns.</li></ul><p>Implementation notes:</p><ul><li>Be precise about what is implemented now versus reserved. Route-level entitlement gating and license import are demonstrable; any SDK billing helper that still throws must be labeled as reserved/planned until implemented.</li><li>Keep committed demo keys clearly marked as demo-only.</li><li>Include copy-pasteable local test steps in docs, not just in source comments.</li></ul><h2 id="repository-and-default-install-model" tabindex="-1">Repository and default-install model <a class="header-anchor" href="#repository-and-default-install-model" aria-label="Permalink to &quot;Repository and default-install model&quot;">​</a></h2><p>The shippable examples should move out of the main platform repository, but they should still be installed by default for local development and fresh self-hosted instances that use the default plugin set.</p><p>Recommended structure:</p><ol><li>Use separate first-party example plugin repositories, or one first-party examples repository with one directory per plugin.</li><li>Publish/pin each example through the plugin registry.</li><li>Add the desired examples to the default install configuration used by <code>scripts/install-plugins.ts</code> / <code>sv plugin add</code> workflows.</li><li>Keep minimal deterministic fixtures in the platform repository only where tests need local source without network access.</li><li>Make the distinction explicit in docs: <ul><li>shippable examples live outside the platform repository;</li><li>test fixtures may live inside the platform repository;</li><li>default-installed examples are resolved from the registry/default install configuration.</li></ul></li></ol><p>The default-installed examples should be pinned by commit/ref and content hash where the registry supports provenance. Floating references are inappropriate for CI and reproducible installs.</p><h2 id="runtime-manifest-cleanup" tabindex="-1">Runtime manifest cleanup <a class="header-anchor" href="#runtime-manifest-cleanup" aria-label="Permalink to &quot;Runtime manifest cleanup&quot;">​</a></h2><p>Current manifest schema accepts runtime values that are not implemented. The code should stop accepting future runtime values until those runtimes are implemented.</p><p>Code should accept:</p><ul><li><code>native</code></li></ul><p>Docs may continue describing future runtime concepts as planned/deferred:</p><ul><li><code>static</code></li><li><code>iframe-local</code></li><li><code>iframe-remote</code></li><li><code>external</code></li></ul><p>Implementation tasks:</p><ol><li>Change the manifest schema runtime enum to accept only <code>native</code>.</li><li>Update generated/exported manifest types accordingly.</li><li>Update manifest validation tests that currently expect future runtime values to pass.</li><li>Update plugin development docs so the manifest reference lists only currently accepted code values, with a separate future-runtimes note.</li><li>Update the SRS/runtime design docs to distinguish implemented manifest values from planned runtime models.</li><li>Check scaffolding code and template docs for runtime choices.</li><li>Run docs parity and manifest validation checks.</li></ol><p>This cleanup is intentionally separate from implementing the example plugins. It can land before the examples are externalized.</p><h2 id="implementation-phases" tabindex="-1">Implementation phases <a class="header-anchor" href="#implementation-phases" aria-label="Permalink to &quot;Implementation phases&quot;">​</a></h2><h3 id="phase-1-documentation-and-task-setup" tabindex="-1">Phase 1: Documentation and task setup <a class="header-anchor" href="#phase-1-documentation-and-task-setup" aria-label="Permalink to &quot;Phase 1: Documentation and task setup&quot;">​</a></h3><p>Deliverables:</p><ul><li>This planning document.</li><li>Roadmap and epic task entries for the implementation work.</li><li>Updated plugin development docs that preview the new example set.</li></ul><p>Review checklist:</p><ul><li>The plan clearly separates current implementation from future runtimes.</li><li>The overlay size decision is documented as three plugins.</li><li>No source code changes are mixed into the planning-only task.</li></ul><h3 id="phase-2-runtime-manifest-cleanup" tabindex="-1">Phase 2: Runtime manifest cleanup <a class="header-anchor" href="#phase-2-runtime-manifest-cleanup" aria-label="Permalink to &quot;Phase 2: Runtime manifest cleanup&quot;">​</a></h3><p>Deliverables:</p><ul><li>Manifest schema accepts only <code>runtime: &quot;native&quot;</code>.</li><li>Docs continue to mention deferred runtime models without presenting them as accepted code values.</li><li>Tests updated for the tighter schema.</li></ul><p>Review checklist:</p><ul><li>Existing first-party plugins validate.</li><li>Invalid future runtime values fail manifest validation.</li><li>Docs explain how future runtime models will return later.</li></ul><h3 id="phase-3-expand-in-repo-examples-or-fixtures" tabindex="-1">Phase 3: Expand in-repo examples or fixtures <a class="header-anchor" href="#phase-3-expand-in-repo-examples-or-fixtures" aria-label="Permalink to &quot;Phase 3: Expand in-repo examples or fixtures&quot;">​</a></h3><p>Deliverables:</p><ul><li>Add <code>Example: Overlay Small</code>, <code>Example: Overlay Medium</code>, <code>Example: Overlay Large</code>, and <code>Example: Minimal</code>.</li><li>Expand <code>Example: API</code> and <code>Example: Monetized</code>.</li><li>Keep <code>Example: Basic</code> behavior stable.</li></ul><p>Review checklist:</p><ul><li><code>pnpm generate</code> composes all examples correctly.</li><li>Overlay plugins exercise all three <code>overlaySize</code> values.</li><li>Minimal plugin composes under the minimal route group.</li><li>API provider uniqueness still holds.</li><li>Monetized plugin paywall flow remains covered by E2E tests.</li></ul><h3 id="phase-4-externalize-shippable-example-sources" tabindex="-1">Phase 4: Externalize shippable example sources <a class="header-anchor" href="#phase-4-externalize-shippable-example-sources" aria-label="Permalink to &quot;Phase 4: Externalize shippable example sources&quot;">​</a></h3><p>Deliverables:</p><ul><li>Move shippable examples into first-party external repos or a first-party examples repository.</li><li>Add registry entries with pinned provenance.</li><li>Add default install configuration so the examples are installed by default.</li><li>Keep or add local fixtures needed for deterministic tests.</li></ul><p>Review checklist:</p><ul><li>Fresh install/dev flow includes the examples by default.</li><li>CI does not depend on floating network state.</li><li>Documentation points developers to the external example sources.</li><li>Runtime tests still have deterministic local fixtures.</li></ul><h3 id="phase-5-documentation-polish-and-cross-links" tabindex="-1">Phase 5: Documentation polish and cross-links <a class="header-anchor" href="#phase-5-documentation-polish-and-cross-links" aria-label="Permalink to &quot;Phase 5: Documentation polish and cross-links&quot;">​</a></h3><p>Deliverables:</p><ul><li>Update <code>docs/plugin-development.md</code> example plugin table.</li><li>Update <code>docs/epics/example-plugins.md</code> or create new task entries if the old epic remains complete.</li><li>Update relevant RFC status notes if needed.</li><li>Add links from API, overlay, minimal shell, and monetization sections to the corresponding examples.</li></ul><p>Review checklist:</p><ul><li>Developers can discover which example teaches which feature.</li><li>End-user-facing language uses &quot;app&quot; where appropriate.</li><li>Developer docs use &quot;plugin&quot; consistently for architecture and manifest concepts.</li></ul><h2 id="suggested-task-breakdown" tabindex="-1">Suggested task breakdown <a class="header-anchor" href="#suggested-task-breakdown" aria-label="Permalink to &quot;Suggested task breakdown&quot;">​</a></h2><p>These are candidate tasks for roadmap/epic planning. Stable epic task IDs should be assigned when the roadmap is updated.</p><table tabindex="0"><thead><tr><th>Candidate task</th><th>Scope</th></tr></thead><tbody><tr><td>Example plugin plan</td><td>Add this document and task planning entries.</td></tr><tr><td>Tighten runtime manifest enum</td><td>Accept only <code>native</code> in code; keep future runtimes in docs.</td></tr><tr><td>Overlay example plugins</td><td>Add small, medium, and large overlay examples.</td></tr><tr><td>Minimal example plugin</td><td>Add full-bleed minimal-shell example.</td></tr><tr><td>API example expansion</td><td>Add richer endpoint examples and developer-facing docs.</td></tr><tr><td>Monetized example expansion</td><td>Clarify billing/entitlement behavior and local test flow.</td></tr><tr><td>External default example plugin install</td><td>Move shippable sources out of repo; install by default.</td></tr><tr><td>Example fixture/test separation</td><td>Keep deterministic local fixtures where runtime tests need it.</td></tr><tr><td>Plugin development documentation refresh</td><td>Update example table, links, and future-runtime language.</td></tr></tbody></table><h2 id="open-decisions" tabindex="-1">Open decisions <a class="header-anchor" href="#open-decisions" aria-label="Permalink to &quot;Open decisions&quot;">​</a></h2><ul><li>Whether the external examples live in one repository or one repository per example plugin.</li><li>Whether externalized examples use <code>type: &quot;sovereign&quot;</code> from the start or keep a transitional in-repo <code>platform</code> type until registry installation is wired.</li><li>Whether <code>static</code> should be removed from accepted code values along with the iframe and external runtime values. The strict plan is to accept only <code>native</code> until any non-native runtime is implemented.</li><li>Whether the API example should demonstrate API-key auth, signed requests, or only public deterministic endpoints.</li><li>Whether example plugins remain enabled in production defaults or only in development/demo presets.</li></ul>',113)])])}const h=t(o,[["render",n]]);export{m as __pageData,h as default};
